                               << "' 'every'/'along' cannot be used if the "
                                  "constrained value is a tensor_view";
    return success();
  }

  // TileType
  auto tileType = llvm::dyn_cast<cuda_tile::TileType>(assumeOp.getType());
  if (!tileType)
    return op->emitOpError() << "'" << name
